package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.PrintStream;

import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    private CSVFormat csvFormat;
    private PrintStream originalOut;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.newFormat(',');
        // Save original System.out
        originalOut = System.out;
    }

    @AfterEach
    void tearDown() {
        // Restore original System.out
        System.setOut(originalOut);
    }

    @Test
    void testPrinterNotNull() throws IOException {
        CSVPrinter printer = csvFormat.printer();
        assertNotNull(printer);
    }

    @Test
    void testPrinterUsesSystemOut() throws IOException {
        // Wrap System.out to detect usage
        PrintStream spyOut = spy(System.out);
        System.setOut(spyOut);

        CSVPrinter printer = csvFormat.printer();
        assertNotNull(printer);

        // The printer should be constructed with System.out and this CSVFormat instance
        // We can check that the printer's out is System.out (indirectly)
        // Since CSVPrinter class is not mocked, we can't access its internals easily
        // But we can check that no exceptions thrown and printer is created successfully
    }

}
